from __future__ import annotations

from dashboard_a9.runtime import execute_block

BLOCK_CODE = 'with tab5:\n    if tab_funil_movel_ativa:\n        render_bloco_cotacoes_funil_movel()\n        render_bloco_backlog_fixa_pme()\n        limpar_objetos_runtime_dashboard()\n\n    def build_home_source_filters_html(info_text: object, titulo: str = "Filtros de Origem") -> str:\n        partes = [\n            str(parte).strip()\n            for parte in str(info_text or "").split("|")\n            if str(parte).strip()\n        ]\n        if not partes:\n            return ""\n\n        chips = "".join(\n            f"""\n            <span style="\n                display:inline-flex;\n                align-items:center;\n                padding:0.34rem 0.72rem;\n                border-radius:999px;\n                border:1px solid rgba(121,14,9,0.16);\n                background:linear-gradient(135deg, rgba(121,14,9,0.09), rgba(121,14,9,0.03));\n                color:#6D201A;\n                font-size:12px;\n                font-weight:600;\n                line-height:1.1;\n                white-space:nowrap;\n            ">{escape(parte)}</span>\n            """\n            for parte in partes\n        )\n        return f"""\n        <div style="\n            display:flex;\n            flex-wrap:wrap;\n            align-items:center;\n            gap:8px;\n            margin:0.15rem 0 0.8rem 0;\n        ">\n            <span style="\n                font-size:11px;\n                font-weight:700;\n                text-transform:uppercase;\n                letter-spacing:0.08em;\n                color:#790E09;\n            ">{escape(str(titulo))}</span>\n            {chips}\n        </div>\n        """\n\n    def render_home_synced_selectbox(\n        filter_label_text: str,\n        widget_label: str,\n        options,\n        source_key: str,\n        home_key: str,\n        default_value=None\n    ):\n        opcoes = list(options or [])\n        if not opcoes:\n            return None\n\n        valor_padrao = default_value if default_value in opcoes else opcoes[0]\n        valor_source = st.session_state.get(source_key, valor_padrao)\n        if valor_source not in opcoes:\n            valor_source = valor_padrao\n\n        valor_home = st.session_state.get(home_key)\n        valor_inicial = valor_home if valor_home in opcoes else valor_source\n        index_inicial = opcoes.index(valor_inicial) if valor_inicial in opcoes else 0\n\n        def _sincronizar_filtro_home(chave_origem: str, chave_home: str) -> None:\n            valor_widget = st.session_state.get(chave_home)\n            if valor_widget in opcoes:\n                st.session_state[chave_origem] = valor_widget\n\n        render_filter_label(filter_label_text)\n        selecionado = st.selectbox(\n            widget_label,\n            options=opcoes,\n            index=index_inicial,\n            key=home_key,\n            label_visibility="collapsed",\n            on_change=_sincronizar_filtro_home,\n            args=(source_key, home_key)\n        )\n\n        if selecionado != valor_source:\n            st.session_state[source_key] = selecionado\n\n        return selecionado\n\ngc.collect()\n\n'


def render(namespace: dict[str, object]) -> None:
    execute_block(BLOCK_CODE, namespace, 'funil_movel_final')
